/// Transform: aggregate
pub fn transform_weighted_values(df: DataFrame) -> nexcore_error::Result<DataFrame> {
    tracing::info!(stage = "weighted-values", "Aggregating data");
    let aggregated = df
        .group_by(&["head_id"])
        .map_err(|e| nexcore_error::nexerror!("{e}"))?
        .agg(&[Agg::Sum("value_vector".into())])
        .map_err(|e| nexcore_error::nexerror!("{e}"))?;
    Ok(aggregated)
}
